class Animal {
    // speakMethod definition
    void speak() {
        System.out.println("...");
    }
}

// DogClass definition
class Dog extends Animal {
    @Override
    // speakMethod definition
    void speak() {
        System.out.println("Woof");
    }
    void fetch() {
        System.out.println("Fetched the ball!");
    }
}

// MainClass definition
public class Main {
    public static void main(String[] args) {
        Animal a = new Dog();  // Upcast(Automatic)
        a.speak();   // OK → Woof(Dog's method at runtime)
        // a.fetch(); // Compilation error! fetch() does not exist in Animal type
    }
}

Animal a = new Dog();  // Upcast
Dog d = (Dog) a;       // Downcast(Success: Originally a Dog)
d.fetch();             // OK → Fetched the ball!

Animal a2 = new Cat();
// Dog d2 = (Dog) a2;  // Runtime error! ClassCastException
// a2 is actually a Cat instance so it cannot be cast to Dog

Animal a = new Dog();

// Conditional branching
if (a instanceof Dog) {
    Dog d = (Dog) a;  // Safe downcast
    d.fetch();
}

if (a instanceof Cat) {
    // This is not executed(a is a Dog)
    Cat c = (Cat) a;
}

Animal nullAnimal = null;
System.out.println(nullAnimal instanceof Animal); // false

