// AnimalClass definition
class Animal {
    String name;
    Animal(String name) { this.name = name; }
    // speakMethod definition
    void speak() { System.out.println(name + ": ..."); }
}

// DogClass definition
class Dog extends Animal {
    Dog(String name) { super(name); }
    @Override
    // speakMethod definition
    void speak() { System.out.println(name + ": Woof"); }
}

// CatClass definition
class Cat extends Animal {
    Cat(String name) { super(name); }
    @Override
    void speak() { System.out.println(name + ": Meow"); }
}

// BirdClass definition
class Bird extends Animal {
    Bird(String name) { super(name); }
    @Override
    void speak() { System.out.println(name + ": Tweet tweet"); }
}

// MainClass definition
public class Main {
    public static void main(String[] args) {
        Animal[] animals = {
            new Dog("Pochi"),
            new Cat("Tama"),
            new Bird("Pippi")
        };
        // Enhanced for loop(Process all elements in the collection in order)
        for (Animal a : animals) {
            a.speak();  // speak() corresponding to each object's type is called
        }
    }
}
// Output:
// Pochi: Woof
// Tama: Meow
// Pippi: Tweet tweet

// PrinterClass definition
class Printer {
    // AnimalType argument → Can accept Dog, Cat, Bird, or anything
    // printAnimalSoundMethod definition
    static void printAnimalSound(Animal animal) {
        System.out.print(animal.name + "'s sound: ");
        animal.speak();
    }

    // mainMethod definition
    public static void main(String[] args) {
        printAnimalSound(new Dog("Pochi"));   // Pochi's sound: Pochi: Woof
        printAnimalSound(new Cat("Tama"));   // Tama's sound: Tama: Meow
        printAnimalSound(new Bird("Pippi")); // Pippi's sound: Pippi: Tweet tweet
    }
}

