// PaymentInterface definition
interface Payment {
    void pay(int amount);
}

// CreditCardClass definition
class CreditCard implements Payment {
    @Override
    // payMethod definition
    public void pay(int amount) {
        System.out.println("By credit card " + amount + " yen payment");
    }
}

// BankTransferClass definition
class BankTransfer implements Payment {
    @Override
    // payMethod definition
    public void pay(int amount) {
        System.out.println("By bank transfer " + amount + " yen payment");
    }
}

// EMoneyClass definition
class EMoney implements Payment {
    @Override
    public void pay(int amount) {
        System.out.println("By e-money " + amount + " yen payment");
    }
}

// ShopClass definition
public class Shop {
    static void checkout(Payment payment, int amount) {
        payment.pay(amount);  // Same invocation regardless of payment method
    }

    public static void main(String[] args) {
        checkout(new CreditCard(), 5000);
        checkout(new BankTransfer(), 3000);
        checkout(new EMoney(), 1000);
    }
}

// EmployeeClass definition
abstract class Employee {
    String name;
    int baseSalary;

    Employee(String name, int baseSalary) {
        this.name = name;
        this.baseSalary = baseSalary;
    }
    abstract int calculateBonus();  // Implemented in subclass

    // totalSalaryMethod definition
    int totalSalary() {
        return baseSalary + calculateBonus();  // CommonProcessing
    }
}

// ManagerClass definition
class Manager extends Employee {
    Manager(String name) { super(name, 500000); }
    @Override
    // calculateBonusMethod definition
    int calculateBonus() { return 200000; }
}

// EngineerClass definition
class Engineer extends Employee {
    Engineer(String name) { super(name, 400000); }
    @Override
    int calculateBonus() { return 100000; }
}

// MainClass definition
public class Main {
    public static void main(String[] args) {
        Employee[] staff = { new Manager("Tanaka"), new Engineer("Suzuki") };
        // Enhanced for loop(Process all elements in the collection in order)
        for (Employee e : staff) {
            System.out.println(e.name + ": " + e.totalSalary() + " yen");
        }
    }
}
// Output:
// Tanaka: 700000 yen
// Suzuki: 500000 yen

